const express = require('express');
const router = express.Router();
const tasksService = require('./service').service;
router.post('/', (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'BAD_REQUEST', 'Name is required');
  const task = tasksService.createTask(req.params.projectId, { name: req.body.name, status: 'todo' });
  res.status(201).json({ task });
});
router.patch('/:taskId', (req, res) => {
  const task = tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, req.body.status);
  if (!task) return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  res.json({ task });
});
router.get('/', (req, res) => {
  const tasks = tasksService.getTasksByProjectId(req.params.projectId);
  if (!tasks) return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  const filteredTasks = tasks.filter(task => task.status === 'done');
  res.json({ tasks: filteredTasks });
});
module.exports = { router };

const express = require('express');
const router = express.Router();
const membersService = require('./service').service;
router.post('/', (req, res) => {
  if (!req.body.userId || !req.body.role) return sendError(res, 400, 'BAD_REQUEST', 'UserId and role are required');
  const member = membersService.addMember(req.params.projectId, req.body);
  res.status(201).json({ member });
});
module.exports = { router };

const express = require('express');
const router = express.Router();
const commentsService = require('./service').service;
router.post('/', (req, res) => {
  if (!req.body.message) return sendError(res, 400, 'BAD_REQUEST', 'Message is required');
  const comment = commentsService.addComment(req.params.projectId, req.params.taskId, { message: req.body.message });
  res.status(201).json({ comment });
});
module.exports = { router };

const comments = [];
export function addComment(projectId, taskId, { message }) {
  const id = randomUUID();
  const comment = { id, projectId, taskId, message };
  comments.push(comment);
  return comment;
}

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

exports.sendError = sendError;
